// // This module performs a NAND operation on the bits of A and a NOR operation on the bits of B, then outputs the result of an XOR between these two operations.
module top_module(
    input [1:0] A,
    input [1:0] B,
    output reg X
);wire C1 = A[0] & A[1];
    wire C2 = B[0] | B[1];

    always @(*) begin
        X = C1 ^ C2;
    end

endmodule
